import { cn } from "@/lib/utils";
import { ImageOverlay } from "@/registry/new-york/image-overlay/image-overlay";
import { LightboxImageClient } from "@/registry/new-york/lightbox-image/lightbox-image-client";
import { LightboxTrigger } from "@/registry/new-york/lightbox-image/lightbox-trigger";
import type { LightboxSlide } from "@/registry/new-york/lightbox-image/types";
import { StaticImageData } from "next/image";

interface LightboxImageProps {
  src: string | StaticImageData;
  alt: string;
  caption?: React.ReactNode;
  enableLightbox?: boolean;
  gallery?: LightboxSlide[];
  galleryIndex?: number;
  priority?: boolean;
  className?: string;
  sizes?: string;
  maximizeIcon?: React.ReactNode;
}

export function LightboxImage({
  src,
  alt,
  caption,
  enableLightbox = false,
  gallery,
  galleryIndex = 0,
  priority = false,
  className,
  sizes = "(max-width: 640px) 100vw, (max-width: 1024px) 50vw, 640px",
  maximizeIcon,
}: LightboxImageProps) {
  const isStaticImage = typeof src === "object";

  const slide: LightboxSlide = isStaticImage
    ? { ...src, alt, description: caption }
    : { src, alt, description: caption };

  return (
    <figure className="my-6 size-full">
      <LightboxImageClient
        enableLightbox={enableLightbox}
        slide={slide}
        gallery={gallery}
        galleryIndex={galleryIndex}
      >
        <ImageOverlay
          src={src}
          alt={alt}
          sizes={sizes}
          priority={priority}
          className={cn("size-full", className)}
          overlayClassName="rounded-2xl size-full"
          zoomOnHover={enableLightbox}
        >
          {enableLightbox && (
            <LightboxTrigger
              {...(gallery && gallery.length > 0
                ? { slides: gallery, index: galleryIndex }
                : { slide })}
              aria-label="View fullscreen"
            >
              {maximizeIcon || <DefaultMaximizeIcon />}
            </LightboxTrigger>
          )}
        </ImageOverlay>
      </LightboxImageClient>
      {caption && (
        <figcaption className="mt-2 text-sm text-muted-foreground text-center italic">
          {caption}
        </figcaption>
      )}
    </figure>
  );
}

function DefaultMaximizeIcon() {
  return (
    <div className="backdrop-blur-sm bg-background/70 absolute right-3 top-3 z-20 flex h-8 w-8 items-center justify-center rounded-full text-foreground shadow-md transition-all duration-200 ease-in-out hover:bg-primary hover:text-primary-foreground cursor-pointer">
      <svg
        xmlns="http://www.w3.org/2000/svg"
        width={24}
        height={24}
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth={2}
        strokeLinecap="round"
        strokeLinejoin="round"
        className="w-4 h-4"
      >
        <polyline points="15 3 21 3 21 9" />
        <polyline points="9 21 3 21 3 15" />
        <line x1={21} x2={14} y1={3} y2={10} />
        <line x1={3} x2={10} y1={21} y2={14} />
      </svg>
    </div>
  );
}

"use client";

import { usePointerType } from "@/registry/new-york/image-overlay/use-pointer-type";
import { useLightbox } from "@/registry/new-york/lightbox-image/lightbox-provider";
import type { LightboxSlide } from "@/registry/new-york/lightbox-image/types";

interface LightboxImageClientProps {
  enableLightbox: boolean;
  slide: LightboxSlide;
  gallery?: LightboxSlide[];
  galleryIndex: number;
  children: React.ReactNode;
}

export function LightboxImageClient({
  enableLightbox,
  slide,
  gallery,
  galleryIndex,
  children,
}: LightboxImageClientProps) {
  const pointerType = usePointerType();
  const { openSingle, openGallery } = useLightbox();

  const handleClick = () => {
    if (pointerType === "fine" && enableLightbox) {
      if (gallery && gallery.length > 0) {
        openGallery(gallery, galleryIndex);
      } else {
        openSingle(slide);
      }
    }
  };

  return (
    <div onClick={handleClick}>
      {children}
    </div>
  );
}

"use client";

import { createContext, useCallback, useContext, useState } from "react";
import Lightbox, { type Slide } from "yet-another-react-lightbox";
import Video from "yet-another-react-lightbox/plugins/video";
import Captions from "yet-another-react-lightbox/plugins/captions";
import "yet-another-react-lightbox/styles.css";
import "yet-another-react-lightbox/plugins/captions.css";
import type { LightboxContextValue } from "@/registry/new-york/lightbox-image/types";
import { NextJsImageSlide } from "@/registry/new-york/lightbox-image/next-image-slide";

const LightboxContext = createContext<LightboxContextValue | null>(null);

export function useLightbox(): LightboxContextValue {
  const context = useContext(LightboxContext);
  if (!context) {
    throw new Error("useLightbox must be used within a LightboxProvider");
  }
  return context;
}

export function LightboxProvider({ children }: { children: React.ReactNode }) {
  const [isOpen, setIsOpen] = useState(false);
  const [slides, setSlides] = useState<Slide[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);

  const openSingle = useCallback((slide: Slide) => {
    setSlides([slide]);
    setCurrentIndex(0);
    setIsOpen(true);
  }, []);

  const openGallery = useCallback((newSlides: Slide[], index: number) => {
    setSlides(newSlides);
    setCurrentIndex(index);
    setIsOpen(true);
  }, []);

  const close = useCallback(() => {
    setIsOpen(false);
  }, []);

  return (
    <LightboxContext.Provider value={{ openSingle, openGallery, close }}>
      {children}
      <Lightbox
        open={isOpen}
        close={close}
        slides={slides}
        index={currentIndex}
        plugins={[Video, Captions]}
        render={{
          slide: NextJsImageSlide,
        }}
        video={{
          controls: true,
          autoPlay: true,
        }}
        carousel={{
          finite: slides.length === 1,
        }}
        controller={{
          closeOnBackdropClick: true,
        }}
      />
    </LightboxContext.Provider>
  );
}

"use client";

import { Slot } from "@radix-ui/react-slot";
import React from "react";
import type { Slide } from "yet-another-react-lightbox";
import { useLightbox } from "@/registry/new-york/lightbox-image/lightbox-provider";

type SingleSlideProps = {
  slide: Slide;
  slides?: never;
  index?: never;
};

type GalleryProps = {
  slide?: never;
  slides: Slide[];
  index: number;
};

type LightboxTriggerProps = (SingleSlideProps | GalleryProps) &
  Omit<React.ButtonHTMLAttributes<HTMLButtonElement>, "onClick"> & {
    asChild?: boolean;
  };

const LightboxTrigger = React.forwardRef<
  HTMLButtonElement,
  LightboxTriggerProps
>(({ slide, slides, index, asChild, ...rest }, ref) => {
  const { openSingle, openGallery } = useLightbox();

  const handleClick = (e: React.MouseEvent<HTMLButtonElement>) => {
    e.stopPropagation();
    if (slides) {
      openGallery(slides, index);
    } else {
      openSingle(slide);
    }
  };

  const Comp = asChild ? Slot : "button";

  return <Comp ref={ref} onClick={handleClick} {...rest} />;
});
LightboxTrigger.displayName = "LightboxTrigger";

export { LightboxTrigger };

"use client";

import Image, { StaticImageData } from "next/image";
import {
  isImageFitCover,
  isImageSlide,
  useLightboxProps,
  useLightboxState,
  type RenderSlideProps,
  type SlideImage,
} from "yet-another-react-lightbox";

type NextJsSlide = SlideImage & {
  src: string | StaticImageData;
  alt?: string;
  width: number;
  height: number;
  blurDataURL?: string;
};

function isNextJsImage(
  slide: RenderSlideProps["slide"]
): slide is NextJsSlide {
  return (
    isImageSlide(slide) &&
    typeof slide.width === "number" &&
    typeof slide.height === "number"
  );
}

export function NextJsImageSlide({ slide, offset, rect }: RenderSlideProps) {
  const {
    on: { click },
    carousel: { imageFit },
  } = useLightboxProps();

  const { currentIndex } = useLightboxState();

  const cover = isImageSlide(slide) && isImageFitCover(slide, imageFit);

  if (!isNextJsImage(slide)) return undefined;

  const width = !cover
    ? Math.round(
        Math.min(rect.width, (rect.height / slide.height) * slide.width)
      )
    : rect.width;

  const height = !cover
    ? Math.round(
        Math.min(rect.height, (rect.width / slide.width) * slide.height)
      )
    : rect.height;

  return (
    <div style={{ position: "relative", width, height }}>
      <Image
        fill
        alt={slide.alt || ""}
        src={slide}
        loading="eager"
        draggable={false}
        placeholder={slide.blurDataURL ? "blur" : undefined}
        style={{
          objectFit: cover ? "cover" : "contain",
          cursor: click ? "pointer" : undefined,
        }}
        sizes="100vw"
        onClick={
          offset === 0 ? () => click?.({ index: currentIndex }) : undefined
        }
      />
    </div>
  );
}

import type { Slide } from "yet-another-react-lightbox";

export interface LightboxContextValue {
  openSingle: (slide: Slide) => void;
  openGallery: (slides: Slide[], index: number) => void;
  close: () => void;
}

// Re-export Slide type for convenience
export type { Slide as LightboxSlide } from "yet-another-react-lightbox";

export { LightboxProvider, useLightbox } from "@/registry/new-york/lightbox-image/lightbox-provider";
export { LightboxTrigger } from "@/registry/new-york/lightbox-image/lightbox-trigger";
export { LightboxImageClient } from "@/registry/new-york/lightbox-image/lightbox-image-client";
export type { LightboxSlide, LightboxContextValue } from "@/registry/new-york/lightbox-image/types";
